1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
3	const CURSED_SURCHARGE_RATE = 0.5;
4	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
5	const HIGH_ENCHANTMENT_THRESHOLD = 5;
6	const LOYALTY_DISCOUNT_RATE = 0.2;
7	const LOYALTY_YEARS_THRESHOLD = 2;
8	
9	const BASE_PREMIUM: Record<string, number> = {
10	  sword: 100,
11	  amulet: 60,
12	  staff: 80,
13	  potion: 40,
14	  rune: 25,
15	  moonstone: 25,
16	};
17	
18	type Item = { type: string; cursed?: boolean; enchantment?: number; material?: string };
19	type Customer = { yearsWithMHPCO: number };
20	type Step = { op: "quote"; items: Item[] };
21	type Scenario = { customer: Customer; steps: Step[] };
22	
23	const basePremiumOf = (item: Item): number => BASE_PREMIUM[item.type];
24	
25	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
26	const BLOCK_SIZE = 3;
27	const BLOCK_BASE_PREMIUM = 60;
28	
29	const sumBasePremiums = (items: Item[]): number =>
30	  items.reduce((sum, item) => sum + basePremiumOf(item), 0);
31	
32	const componentGroupSubtotalOf = (group: Item[]): number =>
33	  group.length === BLOCK_SIZE ? BLOCK_BASE_PREMIUM : sumBasePremiums(group);
34	
35	const groupByType = (items: Item[]): Map<string, Item[]> => {
36	  const groups = new Map<string, Item[]>();
37	  for (const item of items) {
38	    const existing = groups.get(item.type) ?? [];
39	    existing.push(item);
40	    groups.set(item.type, existing);
41	  }
42	  return groups;
43	};
44	
45	const componentSubtotalOf = (components: Item[]): number =>
46	  [...groupByType(components).values()].reduce(
47	    (sum, group) => sum + componentGroupSubtotalOf(group),
48	    0,
49	  );
50	
51	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
52	
53	const policyBaseOf = (items: Item[]): number => {
54	  const components = items.filter(isComponent);
55	  const mainItems = items.filter((item) => !isComponent(item));
56	  return sumBasePremiums(mainItems) + componentSubtotalOf(components);
57	};
58	
59	const firstInsuranceSurchargeOf = (policyBase: number): number =>
60	  policyBase * FIRST_INSURANCE_SURCHARGE_RATE;
61	
62	const cursedSurchargeOf = (item: Item): number =>
63	  item.cursed ? basePremiumOf(item) * CURSED_SURCHARGE_RATE : 0;
64	
65	const highEnchantmentSurchargeOf = (item: Item): number =>
66	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
67	    ? basePremiumOf(item) * HIGH_ENCHANTMENT_SURCHARGE_RATE
68	    : 0;
69	
70	const surchargesOf = (item: Item): number =>
71	  cursedSurchargeOf(item) + highEnchantmentSurchargeOf(item);
72	
73	const itemSurchargesOf = (items: Item[]): number =>
74	  items.reduce((sum, item) => sum + surchargesOf(item), 0);
75	
76	const roundUpInMHPCOFavor = (amount: number): number => Math.ceil(amount);
77	
78	const loyaltyDiscountOf = (policyBase: number, customer: Customer): number =>
79	  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD ? policyBase * LOYALTY_DISCOUNT_RATE : 0;
80	
81	const quotePremium = (items: Item[], customer: Customer): number => {
82	  const policyBase = policyBaseOf(items);
83	  const rawPremium =
84	    policyBase +
85	    itemSurchargesOf(items) +
86	    firstInsuranceSurchargeOf(policyBase) -
87	    loyaltyDiscountOf(policyBase, customer) +
88	    PROCESSING_FEE;
89	  return roundUpInMHPCOFavor(rawPremium);
90	};
91	
92	export const processScenario = (scenario: Scenario): { results: Array<{ premium: number }> } => {
93	  const results = scenario.steps.map((step) => ({
94	    premium: quotePremium(step.items, scenario.customer),
95	  }));
96	  return { results };
97	};
